  const svelteSource: string = "// In your Svelte component:\nimport BreadcrumbList from \"lily-design-system-svelte-headless/components/BreadcrumbList/BreadcrumbList.svelte\";\n\n<BreadcrumbList>\n  <!-- list children -->\n</BreadcrumbList>\n";
